import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { DefaultMainStageHeader } from "../../utils";
import { stockStrings } from '../config';
import { stockActions } from '../actions';


const style = theme => ({
    root: {
    }
})
class _CategoryMainStage extends Component {
    editBtnHandler = () => {
        const {
            dispatch,
            [stockStrings.stockCategoryEditMode] : stockCategoryEditMode,
            [stockStrings.stockCategoryComponent] : stockCategoryComponent,
        } = this.props;
        stockActions.setStockCategoryEditMode(!Boolean(stockCategoryEditMode))(dispatch);
    }
    cancelEditHandler = () => {
        const {dispatch} = this.props;
        stockActions.setStockCategoryEditMode(false)(dispatch);
    }
    render() {
        const {
            classes, [stockStrings.stockCategoryEditMode] : stockCategoryEditMode
        } = this.props;
        return <DefaultMainStageHeader
                    editMode={stockCategoryEditMode}
                    editBtnHandler={this.editBtnHandler.bind(this)}
                    cancelEditHandler={this.cancelEditHandler.bind(this)}
                />;
    }
}


_CategoryMainStage.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.stockCategoryEditMode]: stockReducer[stockStrings.stockCategoryEditMode],
    [stockStrings.stockCategoryComponent]: stockReducer[stockStrings.stockCategoryComponent],
})


export const CategoryMainStage = connect(mapStateToProps)(withStyles(style)(_CategoryMainStage));
export {CategoryMainStage as default}