import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    headerActions, headerStrings, breadCrumbActions, 
    mainStageHeaderAction, mainStageHeaderStrings, MyTable, 
    EditableCellMapFormat, HighlightedInfo 
} from "../../utils";
import { routeNamesInventory } from '../../routeNames';
import { stockStrings } from '../config';
import { stockActions } from '../actions';
import CategoryMainStage from './CategoryMainStage';


const style = theme => ({
    root: {
        marginTop : 20
    }
})
class _Category extends Component {
    constructor(props) {
        super(props);
        this.state = {
            categories : null,
            categoriesUnusable : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "STOCK CATEGORIES",
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            { name : "Dashboard", path : routeNamesInventory.dashboard},
            { name : "Stocks", path : routeNamesInventory.stocks},
            { name : "Catgories", path : routeNamesInventory.stockCategory},
        ])(dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.components] : [
                CategoryMainStage
            ]
        })(dispatch);
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            dispatch,
        } = this.props;
        stockActions.getStockCategories()(dispatch);
        stockActions.setStockCategoryComponent(this)(dispatch);
    }
    static getDerivedStateFromProps(props, state) {
        const {
            [stockStrings.stockCategories] : stockCategories
        } = props;
        if(!state.categoriesUnusable){
            if(stockCategories){
                state.categoriesUnusable = stockCategories;
                state.categories = stockCategories;
            }
        }else if(JSON.stringify(stockCategories) !== 
        JSON.stringify(state.stockCategoriesUnusable)){
            state.categoriesUnusable = stockCategories;
            state.categories = stockCategories;
        }
        return state;
    }
    cellMapFormat = superProps=>props=><EditableCellMapFormat {...props} {...superProps}/>;
    render() {
        const {
            classes,
            [stockStrings.stockCategoryEditMode] : stockCategoryEditMode
        } = this.props;
        let {categories} = this.state;
        let header = ["SCK", "Name", "Description"];
        let dataMap = ["_id", "name", "description"]
        if(stockCategoryEditMode){
            header = [...header, "Actions"];
            dataMap = [...dataMap, "action"];
            categories = categories ? 
                [...categories.map(item=>({...item, editable:true, delible:true})), {new : true}] :
                [{new : true}];
        }
        return (
            <div className={classes.root}>
                {stockCategoryEditMode && <HighlightedInfo>
                    Deleting a populated categories will default the items to "Unknow" category.
                </HighlightedInfo>}
                <MyTable
                    header={header}
                    dataMap={dataMap}
                    data={categories || []}
                    CellMap={this.cellMapFormat({
                        skipEdit : ['_id']
                    })}
                    />
            </div>
        );
    }
}


_Category.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({stockReducer}) => ({
    [stockStrings.stockCategories] : stockReducer[stockStrings.stockCategories],
    [stockStrings.stockCategoryEditMode] : stockReducer[stockStrings.stockCategoryEditMode],
})


export const Category = connect(mapStateToProps)(withStyles(style)(_Category));
export {Category as default}